const fs = require('fs');
const path = require('path');
const mime = require('mime-types');

function handleFileUpload(req, res) {
  const file = req.files.file;
  const filename = `${Date.now()}-${file.originalname}`;
  const filePath = path.join(__dirname, 'uploads', filename);

  // Validate file type and content
  if (!mime.lookup(file.mimetype) || !allowedFileTypes.includes(file.mimetype)) {
    return res.status(400).send('Invalid file type');
  }

  // Control storage paths
  if (path.resolve(filePath) === path.join(__dirname, 'uploads')) {
    return res.status(403).send('Forbidden');
  }

  // Apply safe size and processing limits
  if (file.size > MAX_FILE_SIZE || file.mimetype === 'application/x-msdownload') {
    return res.status(413).send('File too large');
  }

  // Move the uploaded file to the target path
  fs.renameSync(file.path, filePath);

  // Send a response back to the client
  res.json({
    message: 'File uploaded successfully',
    filename: filename
  });
}